    };

    let codex = CodexConfig {
        command,
        approval_policy,
        thread_sandbox: raw_codex
            .thread_sandbox
            .unwrap_or(defaults.codex.thread_sandbox.clone()),
        turn_sandbox_policy,
        turn_timeout_ms: raw_codex
            .turn_timeout_ms
            .unwrap_or(defaults.codex.turn_timeout_ms),
