#[test]
fn tool_specs_contract() {
    let specs = dynamic_tool::tool_specs();
    assert_eq!(specs.len(), 1, "expected exactly one tool spec");

    let spec = &specs[0];
    assert_eq!(spec["name"], "linear_graphql");

    let description = spec["description"].as_str().unwrap();
    assert!(
